  const result1 = await system.redeemCoupon('SUMMER2024', 'user_001', 150.00);
  console.log('User 001 redeems SUMMER2024:', JSON.stringify(result1, null, 2));

  // Same user tries again — should fail
  const result2 = await system.redeemCoupon('SUMMER2024', 'user_001', 200.00);
  console.log('User 001 redeems SUMMER2024 again:', JSON.stringify(result2, null, 2));

  // Different user redeems same coupon — should succeed
  const result3 = await system.redeemCoupon('SUMMER2024', 'user_002', 99.99);
  console.log('User 002 redeems SUMMER2024:', JSON.stringify(result3, null, 2));

  // Try expired coupon
  const result4 = await system.redeemCoupon('EXPIRED10', 'user_001', 100.00);
  console.log('User 001 redeems EXPIRED10:', JSON.stringify(result4, null, 2));

  // Fixed discount coupon
  const result5 = await system.redeemCoupon('FLAT50', 'user_001', 200.00);
  console.log('User 001 redeems FLAT50:', JSON.stringify(result5, null, 2));

  // Non-existent coupon
  const result6 = await system.redeemCoupon('DOESNOTEXIST', 'user_001', 100.00);
  console.log('Non-existent coupon:', JSON.stringify(result6, null, 2));

  // 4. Test limited coupon depletion
  console.log('\n--- Testing Coupon Depletion (LIMITED3 - max 3 redemptions) ---');
  for (let i = 1; i <= 5; i++) {
    const res = await system.redeemCoupon('LIMITED3', `depletion_user_${i}`, 100.00);
    console.log(`  User ${i}: ${res.success ? 'SUCCESS' : res.error} ${res.success ? `(#${res.redemptionNumber})` : ''}`);
  }

